messages.content:
You are a real-time systems architect specializing in WebSocket APIs.

Given this requirement:
- ID: WA-PROF-003
- Title: Info/Status Text
- Description: Das System MUSS einen kurzen Info-Text im Profil unterstuetzen

Derive WebSocket channels and events needed for real-time features.

Return JSON format:
{
    "channels": [
        {
            "name": "chat/messages",
            "description": "Real-time chat message delivery",
            "subscribe": {
                "name": "ChatMessageReceived",
                "description": "Incoming message from another user",
                "fields": {
                    "message_id": {"type": "string", "description": "Unique message ID"},
                    "sender_id": {"type": "string", "description": "Sender user ID"},
                    "content": {"type": "string", "description": "Message content"},
                    "timestamp": {"type": "string", "format": "date-time"}
                }
            },
            "publish": {
                "name": "SendChatMessage",
                "description": "Send a new message",
                "fields": {
                    "conversation_id": {"type": "string"},
                    "content": {"type": "string"},
                    "type": {"type": "string", "enum": ["text", "image", "file"]}
                }
            },
            "parameters": {
                "conversation_id": "string"
            }
        }
    ]
}

Guidelines:
- Use hierarchical channel names (e.g., "chat/messages", "user/presence", "call/signal")
- subscribe = events FROM server TO client (receiving)
- publish = events FROM client TO server (sending)
- Include all necessary fields with types
- Consider acknowledgment events where needed
- Only include channels directly related to the requirement

Return ONLY valid JSON.

{
  "channels": [
    {
      "name": "user/profile",
      "description": "Real-time profile info/status text updates",
      "subscribe": {
        "name": "ProfileInfoUpdated",
        "description": "Profile info/status text has been updated",
        "fields": {
          "user_id": {
            "type": "string",
            "description": "User ID whose profile info was updated"
          },
          "info_text": {
            "type": "string",
            "description": "Short info/status text displayed in the profile"
          },
          "updated_at": {
            "type": "string",
            "format": "date-time",
            "description": "Update timestamp"
          }
        }
      },
      "publish": [
        {
          "name": "UpdateProfileInfo",
          "description": "Update the short info/status text in the profile",
          "fields": {
            "user_id": {
              "type": "string",
              "description": "User ID updating the info text"
            },
            "info_text": {
              "type": "string",
              "description": "New short info/status text"
            },
            "request_id": {
              "type": "string",
              "description": "Client-generated request ID for acknowledgment correlation"
            }
          }
        },
        {
          "name": "ProfileInfoUpdateAck",
          "description": "Acknowledgment of profile info/status update",
          "fields": {
            "request_id": {
              "type": "string",
              "description": "Client-generated request ID"
            },
            "status": {
              "type": "string",
              "enum": [
                "accepted",
                "rejected"
              ],
              "description": "Acknowledgment status"
            },
            "reason": {
              "type": "string",
              "description": "Optional rejection reason"
            }
          }
        }
      ],
      "parameters": {
        "user_id": "string"
      }
    }
  ]
}

{
  "stories": [
    {
      "id": "US-001",
      "vague_term": "schnell",
      "acceptance_criteria": {
        "given": "das System ist unter Normalbetrieb",
        "when": "der Nutzer die Telefonnummer eingibt und den Verifizierungscode bestätigt",
        "then": "die Registrierung und Verifizierung sind innerhalb von 30 Sekunden abgeschlossen"
      }
    },
    {
      "id": "US-002",
      "vague_term": "besser schützen",
      "acceptance_criteria": {
        "given": "Zwei-Faktor-Authentifizierung ist aktiviert",
        "when": "ein Login ohne gültige 6-stellige PIN erfolgt",
        "then": "der Zugriff wird in 100% der Fälle verweigert"
      }
    },
    {
      "id": "US-003",
      "vague_term": "schnell",
      "acceptance_criteria": {
        "given": "biometrische Entsperrung ist aktiviert",
        "when": "der Nutzer Fingerabdruck oder Face ID verwendet",
        "then": "die Entsperrung erfolgt in <= 2 Sekunden"
      }
    },
    {
      "id": "US-004",
      "vague_term": "nahtlos",
      "acceptance_criteria": {
        "given": "der Nutzer ist auf zwei Geräten angemeldet",
        "when": "eine Nachricht auf Gerät A empfangen wird",
        "then": "die Nachricht wird auf Gerät B innerhalb von 5 Sekunden angezeigt"
      }
    },
    {
      "id": "US-006",
      "vague_term": "persönlich",
      "acceptance_criteria": {
        "given": "der Nutzer lädt ein Profilbild hoch",
        "when": "das Bild gespeichert wird",
        "then": "das Profilbild wird in der Profilansicht in <= 5 Sekunden angezeigt"
      }
    },
    {
      "id": "US-007",
      "vague_term": "klar erkennbar",
      "acceptance_criteria": {
        "given": "ein Anzeigename wurde gesetzt",
        "when": "das Profil im Kontaktverzeichnis angezeigt wird",
        "then": "der Anzeigename wird vollständig und ohne Kürzung angezeigt, sofern er <= 30 Zeichen lang ist"
      }
    },
    {
      "id": "US-008",
      "vague_term": "schnell",
      "acceptance_criteria": {
        "given": "der Nutzer aktualisiert den Info-/Status-Text",
        "when": "er speichert die Änderung",
        "then": "der neue Text ist innerhalb von 5 Sekunden im Profil sichtbar"
      }
    },
    {
      "id": "US-011",
      "vague_term": "Echtzeit",
      "acceptance_criteria": {
        "given": "beide Nutzer sind online",
        "when": "eine Textnachricht gesendet wird",
        "then": "die Nachricht wird beim Empfänger innerhalb von 2 Sekunden zugestellt"
      }
    },
    {
      "id": "US-012",
      "vague_term": "schnell",
      "acceptance_criteria": {
        "given": "der Nutzer nimmt eine Sprachnachricht von <= 30 Sekunden auf",
        "when": "er sie sendet",
        "then": "die Nachricht wird innerhalb von 5 Sekunden nach dem Senden zugestellt"
      }
    },
    {
      "id": "US-014",
      "vague_term": "zuverlässig",
      "acceptance_criteria": {
        "given": "eine gesendete Nachricht wurde bearbeitet",
        "when": "die Änderung gespeichert wird",
        "then": "die bearbeitete Version wird bei allen Empfängern in <= 5 Sekunden angezeigt"
      }
    }
  ]
}
